sources = [
    {"name": "clients.csv", "sha256": "abc", "n_in": 3, "n_clean": 2, "n_quarantine": 1},
    {"name": "tx.csv", "sha256": "def", "n_in": 5, "n_clean": 5, "n_quarantine": 0},
]
for s in sources:
    s["reconcile_ok"] = s["n_in"] == s["n_clean"] + s["n_quarantine"]
manifest = {"run_id": "run-001", "sources": sources}
print(manifest)

def reconcile_sources(sources):
    ok = all(s["n_in"] == s["n_clean"] + s["n_quarantine"] for s in sources)
    return {"reconcile_ok": ok, "sources": sources}
print(reconcile_sources([
    {"name": "a", "n_in": 3, "n_clean": 2, "n_quarantine": 1},
    {"name": "b", "n_in": 2, "n_clean": 1, "n_quarantine": 0},
]))

def run(sources):
    for s in sources:
        if s["n_in"] != s["n_clean"] + s["n_quarantine"]:
            raise SystemExit(1)
    return 0
try:
    print("bad", run([{"n_in": 2, "n_clean": 1, "n_quarantine": 0}]))
except SystemExit as e:
    print("fail closed exit", e.code)
print("good", run([{"n_in": 2, "n_clean": 1, "n_quarantine": 1}]))
